#!/usr/bin/perl
use strict;
use warnings;
use Storable qw(nstore retrieve);
use File::Spec;
use File::Path qw(make_path);
use Digest::SHA qw(sha256_hex);
use CGI;
use CGI::Cookie;
use Fcntl qw(:flock);
use Scalar::Util qw(blessed reftype);

# Configuration
my $SESSION_DIR = '/tmp/perl_sessions';
my $SESSION_TIMEOUT = 3600; # 1 hour
my $SESSION_ID_LENGTH = 64;
my $COOKIE_NAME = 'PERL_SESSION_ID';

# Ensure session directory exists with restricted permissions
unless (-d $SESSION_DIR) {
    make_path($SESSION_DIR, { mode => 0700 })
        or die "Cannot create session directory $SESSION_DIR: $!";
}

# ============================================================
# Session ID Validation
# ============================================================

sub validate_session_id {
    my ($session_id) = @_;

    return 0 unless defined $session_id;

    # Session ID must be exactly 64 hex characters (SHA-256 output)
    return 0 unless $session_id =~ /\A[a-f0-9]{64}\z/;

    return 1;
}

# ============================================================
# Generate a cryptographically secure session ID
# ============================================================

sub generate_session_id {
    my $random_bytes = '';

    # Read from /dev/urandom for cryptographic randomness
    if (open my $urandom, '<:raw', '/dev/urandom') {
        read($urandom, $random_bytes, 64);
        close $urandom;
    } else {
        # Fallback: combine multiple entropy sources
        $random_bytes = join('', map { chr(int(rand(256))) } 1..64);
        $random_bytes .= "$$-$<-" . time() . "-" . rand();
    }

    return sha256_hex($random_bytes . $$ . time());
}

# ============================================================
# Build safe session file path (prevent directory traversal)
# ============================================================

sub get_session_filepath {
    my ($session_id) = @_;

    die "Invalid session ID" unless validate_session_id($session_id);

    my $filename = "sess_$session_id";

    # Construct path safely
    my $filepath = File::Spec->catfile($SESSION_DIR, $filename);

    # Canonicalize and verify the path is within SESSION_DIR
    my $abs_session_dir = File::Spec->rel2abs($SESSION_DIR);
    my $abs_filepath = File::Spec->rel2abs($filepath);

    # Ensure the resolved path starts with the session directory
    unless ($abs_filepath =~ /\A\Q$abs_session_dir\E\//) {
        die "Path traversal attempt detected: $abs_filepath";
    }

    # Additional check: no symlinks in the path
    if (-l $filepath) {
        die "Symlink detected in session path: $filepath";
    }

    return $filepath;
}

# ============================================================
# Validate deserialized session data structure
# ============================================================

sub validate_session_data {
    my ($data) = @_;

    # Must be a plain hash reference (not blessed/object)
    unless (defined $data && ref($data) eq 'HASH' && !blessed($data)) {
        warn "Session data is not a plain HASH reference";
        return 0;
    }

    # Recursively validate all values are safe data-only types
    return _validate_value_recursive($data, 0);
}

sub _validate_value_recursive {
    my ($value, $depth) = @_;

    # Prevent deeply nested structures (DoS protection)
    if ($depth > 10) {
        warn "Session data exceeds maximum nesting depth";
        return 0;
    }

    # Undefined values are acceptable
    return 1 unless defined $value;

    # Non-reference scalars (strings, numbers) are safe
    unless (ref($value)) {
        return 1;
    }

    # Reject blessed objects - only plain data structures allowed
    if (blessed($value)) {
        warn "Blessed object found in session data: " . ref($value);
        return 0;
    }

    my $type = reftype($value);

    if ($type eq 'HASH') {
        # Validate all keys are simple strings
        for my $key (keys %$value) {
            unless (defined $key && !ref($key)) {
                warn "Non-scalar key found in session data";
                return 0;
            }
            # Validate key content (no null bytes, reasonable length)
            if ($key =~ /\0/ || length($key) > 256) {
                warn "Suspicious key in session data";
                return 0;
            }
            return 0 unless _validate_value_recursive($value->{$key}, $depth + 1);
        }
        return 1;
    }
    elsif ($type eq 'ARRAY') {
        for my $item (@$value) {
            return 0 unless _validate_value_recursive($item, $depth + 1);
        }
        return 1;
    }
    elsif ($type eq 'SCALAR' || $type eq 'REF') {
        return _validate_value_recursive($$value, $depth + 1);
    }
    else {
        # Reject CODE, GLOB, IO, FORMAT, REGEXP, etc.
        warn "Disallowed reference type in session data: $type";
        return 0;
    }
}

# ============================================================
# Load session from file using Storable::retrieve
# ============================================================

sub load_session {
    my ($session_id) = @_;

    unless (validate_session_id($session_id)) {
        warn "Attempt to load session with invalid ID";
        return undef;
    }

    my $filepath = eval { get_session_filepath($session_id) };
    if ($@) {
        warn "Session filepath error: $@";
        return undef;
    }

    unless (-f $filepath && -r $filepath) {
        return undef; # Session file doesn't exist
    }

    # Check file ownership (must be owned by current user)
    my @stat = stat($filepath);
    unless (@stat && $stat[4] == $<) {
        warn "Session file not owned by current user: $filepath";
        return undef;
    }

    # Check file permissions (should not be world-readable)
    if ($stat[2] & 0077) {
        warn "Session file has insecure permissions: $filepath";
        return undef;
    }

    # Check file size (prevent loading excessively large files)
    my $max_size = 1024 * 1024; # 1 MB
    if ($stat[7] > $max_size) {
        warn "Session file exceeds maximum size: $filepath";
        return undef;
    }

    # Deserialize using Storable::retrieve with error handling
    my $data = eval {
        local $Storable::Eval = 0;    # Disable eval of code
        local $Storable::Deparse = 0; # Disable code serialization
        retrieve($filepath);
    };

    if ($@ || !defined $data) {
        warn "Failed to deserialize session file $filepath: " . ($@ || 'unknown error');
        unlink $filepath; # Remove corrupted session file
        return undef;
    }

    # Validate the deserialized data structure
    unless (validate_session_data($data)) {
        warn "Session data failed validation for $session_id";
        unlink $filepath; # Remove suspicious session file
        return undef;
    }

    # Check session expiration
    if (exists $data->{_expires} && defined $data->{_expires}) {
        unless ($data->{_expires} =~ /\A\d+\z/ && $data->{_expires} > time()) {
            unlink $filepath; # Remove expired session
            return undef;
        }
    } else {
        # No expiration set - treat as invalid
        warn "Session missing expiration timestamp: $session_id";
        unlink $filepath;
        return undef;
    }

    # Check creation time is reasonable
    if (exists $data->{_created} && defined $data->{_created}) {
        unless ($data->{_created} =~ /\A\d+\z/ && $data->{_created} <= time()) {
            warn "Session has future creation time: $session_id";
            unlink $filepath;
            return undef;
        }
    }

    # Update last access time
    $data->{_last_access} = time();

    return $data;
}

# ============================================================
# Save session to file using Storable::nstore
# ============================================================

sub save_session {
    my ($session_id, $data) = @_;

    unless (validate_session_id($session_id)) {
        die "Cannot save session with invalid ID";
    }

    unless (validate_session_data($data)) {
        die "Cannot save invalid session data";
    }

    my $filepath = get_session_filepath($session_id);

    # Set metadata
    $data->{_last_modified} = time();
    $data->{_expires} = time() + $SESSION_TIMEOUT unless exists $data->{_expires};

    # Write to a temporary file first, then rename (atomic operation)
    my $tmpfile = "$filepath.tmp.$$";

    eval {
        # Use nstore for network-byte-order portability
        local $Storable::Eval = 0;
        local $Storable::Deparse = 0;
        nstore($data, $tmpfile)
            or die "nstore failed: $!";
    };

    if ($@) {
        unlink $tmpfile;
        die "Failed to serialize session data: $@";
    }

    # Set restrictive permissions on temp file
    chmod(0600, $tmpfile)
        or do { unlink $tmpfile; die "Cannot set permissions on $tmpfile: $!" };

    # Atomic rename
    rename($tmpfile, $filepath)
        or do { unlink $tmpfile; die "Cannot rename $tmpfile to $filepath: $!" };

    return 1;
}

# ============================================================
# Create a new session
# ============================================================

sub create_session {
    my (%initial_data) = @_;

    my $session_id = generate_session_id();
    my $now = time();

    my $data = {
        %initial_data,
        _session_id   => $session_id,
        _created      => $now,
        _last_access  => $now,
        _last_modified => $now,
        _expires      => $now + $SESSION_TIMEOUT,
    };

    # Validate initial data before saving
    unless (validate_session_data($data)) {
        die "Initial session data failed validation";
    }

    save_session($session_id, $data);

    return ($session_id, $data);
}

# ============================================================
# Destroy a session
# ============================================================

sub destroy_session {
    my ($session_id) = @_;

    unless (validate_session_id($session_id)) {
        warn "Cannot destroy session with invalid ID";
        return 0;
    }

    my $filepath = eval { get_session_filepath($session_id) };
    if ($@) {
        warn "Session filepath error during destroy: $@";
        return 0;
    }

    if (-f $filepath) {
        unlink $filepath or warn "Cannot remove session file $filepath: $!";
    }

    return 1;
}

# ============================================================
# Get session ID from cookie
# ============================================================

sub get_session_id_from_cookie {
    my %cookies = CGI::Cookie->fetch();

    if (exists $cookies{$COOKIE_NAME}) {
        my $session_id = $cookies{$COOKIE_NAME}->value();
        if (validate_session_id($session_id)) {
            return $session_id;
        } else {
            warn "Invalid session ID received from cookie";
        }
    }

    return undef;
}

# ============================================================
# Create session cookie
# ============================================================

sub create_session_cookie {
    my ($session_id) = @_;

    die "Invalid session ID for cookie" unless validate_session_id($session_id);

    my $cookie = CGI::Cookie->new(
        -name     => $COOKIE_NAME,
        -value    => $session_id,
        -expires  => "+${SESSION_TIMEOUT}s",
        -path     => '/',
        -httponly  => 1,
        -secure   => 1,
        -samesite => 'Strict',
    );

    return $cookie;
}

# ============================================================
# Clean up expired sessions
# ============================================================

sub cleanup_expired_sessions {
    opendir(my $dh, $SESSION_DIR) or do {
        warn "Cannot open session directory: $!";
        return;
    };

    my $cleaned = 0;
    while (my $entry = readdir($dh)) {
        next unless $entry =~ /\Asess_[a-f0-9]{64}\z/;

        my $filepath = File::Spec->catfile($SESSION_DIR, $entry);
        next if -l $filepath; # Skip symlinks

        my @stat = stat($filepath);
        next unless @stat;

        # Remove files older than 2x timeout
        if (time() - $stat[9] > $SESSION_TIMEOUT * 2) {
            unlink $filepath;
            $cleaned++;
        }
    }
    closedir($dh);

    return $cleaned;
}

# ============================================================
# Main CGI handler / demonstration
