sub handle_request {
    my $cgi = CGI->new();

    my $session_id = get_session_id_from_cookie();
    my $session_data;
    my $is_new_session = 0;

    # Try to load existing session
    if (defined $session_id) {
        $session_data = load_session($session_id);
    }

    # Create new session if needed
    unless (defined $session_data) {
        ($session_id, $session_data) = create_session();
        $is_new_session = 1;
    }

    # Example: track page views
    $session_data->{page_views} = ($session_data->{page_views} || 0) + 1;

    # Example: store user action from query parameter
    my $action = $cgi->param('action') // '';
    if ($action eq 'set_name') {
        my $name = $cgi->param('name') // '';
        # Sanitize input before storing in session
        $name =~ s/[^\w\s\-\.\@]//g;
        $name = substr($name, 0, 100); # Limit length
        $session_data->{username} = $name if length($name) > 0;
    }
